const fs = require("node:fs");
const path = require("node:path");

const locations = [
  ["cache", process.env.npm_config_cache || process.env.NPM_CONFIG_CACHE],
  ["prefix", process.env.npm_config_prefix || process.env.NPM_CONFIG_PREFIX]
];

for (const [name, configured] of locations) {
  if (!configured) {
    throw new Error(`missing npm ${name} setting`);
  }

  prepareNpmLocation(name, path.resolve(configured));
}

function prepareNpmLocation(name, target) {
  if (target.startsWith("/proc/")) {
    fs.chmodSync(target, 0o700);
  }

  fs.mkdirSync(target, { recursive: true });
  fs.writeFileSync(path.join(target, `${name}.probe`), "ok\n");
}
